+            bindings: vec![
+                HelpBinding {
+                    keys: "Esc",
+                    description: "Close help overlay",
+                },
+                HelpBinding {
+                    keys: "?",
+                    description: "Toggle help overlay",
+                },
+            ],
+        },
+        Overlay::Voi => ContextualHelp {
+            title: "VOI Overlay",
+            screen_hint: "Value-of-information scheduler details.",
+            bindings: vec![
+                HelpBinding {
